package format

import (
	"bytes"
	"fmt"
	"sort"

	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/terraform"
)

// CompactDiffFormatter produces a condensed, summary-style diff output
// for terraform plan, showing only resource-level changes without
// attribute-level detail.
type CompactDiffFormatter struct{}

// Format returns a compact formatted summary of the plan's resource changes.
// It groups changes by action type and outputs one line per resource change,
// ending with a summary of the total changes.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *terraform.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return ""
	}

	var buf bytes.Buffer

	// Group resources by action
	actionGroups := make(map[plans.Action][]*plans.ResourceInstanceChangeSrc)
	for _, rc := range plan.Changes.Resources {
		if rc.DeposedKey != "" {
			// Skip deposed resources
			continue
		}
		actionGroups[rc.Action] = append(actionGroups[rc.Action], rc)
	}

	// Define the order in which to display actions
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.Delete,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.CreateThenForget,
		plans.Forget,
		plans.Read,
		plans.NoOp,
	}

	// Sort resources within each action group
	for _, resources := range actionGroups {
		sort.Slice(resources, func(i, j int) bool {
			return resources[i].Addr.String() < resources[j].Addr.String()
		})
	}

	// Output resources grouped by action
	for _, action := range actionOrder {
		resources, ok := actionGroups[action]
		if !ok || len(resources) == 0 {
			continue
		}

		// Only show non-NoOp actions
		if action != plans.NoOp {
			buf.WriteString(fmt.Sprintf("\n# %s\n", actionSymbolAndName(action)))
			for _, rc := range resources {
				buf.WriteString(fmt.Sprintf("  %s\n", rc.Addr.String()))
			}
		}
	}

	// Add summary
	buf.WriteString("\n# Summary\n")
	summary := countChanges(actionGroups)
	for _, text := range summary {
		buf.WriteString(fmt.Sprintf("  %s\n", text))
	}

	return buf.String()
}

// actionSymbolAndName returns a human-readable name for an action.
func actionSymbolAndName(action plans.Action) string {
	switch action {
	case plans.Create:
		return "[+] Resources to create"
	case plans.Update:
		return "[~] Resources to update"
	case plans.Delete:
		return "[-] Resources to delete"
	case plans.DeleteThenCreate:
		return "[∓] Resources to replace"
	case plans.CreateThenDelete:
		return "[±] Resources to replace"
	case plans.CreateThenForget:
		return "[+.] Resources to create and forget"
	case plans.Forget:
		return "[.] Resources to forget"
	case plans.Read:
		return "[<=] Resources to read"
	case plans.NoOp:
		return "[no change] Resources with no changes"
	default:
		return "[?] Resources with unknown action"
	}
}

// countChanges returns a summary of the changes by action type.
func countChanges(actionGroups map[plans.Action][]*plans.ResourceInstanceChangeSrc) []string {
	var summary []string

	createCount := len(actionGroups[plans.Create])
	updateCount := len(actionGroups[plans.Update])
	deleteCount := len(actionGroups[plans.Delete])
	replaceCount := len(actionGroups[plans.DeleteThenCreate]) + len(actionGroups[plans.CreateThenDelete])
	forgetCount := len(actionGroups[plans.Forget]) + len(actionGroups[plans.CreateThenForget])
	readCount := len(actionGroups[plans.Read])

	if createCount > 0 {
		summary = append(summary, fmt.Sprintf("%d create", createCount))
	}
	if updateCount > 0 {
		summary = append(summary, fmt.Sprintf("%d update", updateCount))
	}
	if deleteCount > 0 {
		summary = append(summary, fmt.Sprintf("%d delete", deleteCount))
	}
	if replaceCount > 0 {
		summary = append(summary, fmt.Sprintf("%d replace", replaceCount))
	}
	if forgetCount > 0 {
		summary = append(summary, fmt.Sprintf("%d forget", forgetCount))
	}
	if readCount > 0 {
		summary = append(summary, fmt.Sprintf("%d read", readCount))
	}

	if len(summary) == 0 {
		summary = append(summary, "No changes")
	}

	return summary
}

