			Mode: addrs.ManagedResourceMode,
			Type: "aws_instance",
			Name: "primary",
		}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
		ProviderAddr: addrs.AbsProviderConfig{
			Provider: addrs.NewDefaultProvider("aws"),
			Module:   addrs.RootModule,
		},
		ChangeSrc: plans.ChangeSrc{
			Action: plans.DeleteThenCreate,
		},
	})

	schemas := &schemarepo.Schemas{}

	output := formatter.Format(plan, schemas)

	// Check for replace in output
	if !strings.Contains(output, "replace") {
		t.Errorf("Expected 'replace' in output, got: %s", output)
	}
	if !strings.Contains(output, "aws_instance.primary") {
		t.Errorf("Expected 'aws_instance.primary' in output, got: %s", output)
	}
	if !strings.Contains(output, "1 replace") {
		t.Errorf("Expected '1 replace' in output, got: %s", output)
	}
}

